import{_ as l,c as o,o as t,a4 as i}from"./chunks/framework.I1cCAST3.js";const a="/assets/plugin.VVawqkM_.png",u=JSON.parse('{"title":"扩展管理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/plugin/index.md","filePath":"docs/manage/plugin/index.md"}'),r={name:"docs/manage/plugin/index.md"},s=i('<h1 id="扩展管理" tabindex="-1">扩展管理 <a class="header-anchor" href="#扩展管理" aria-label="Permalink to &quot;扩展管理&quot;">​</a></h1><p>安装和管理扩展，定制和扩展 Chaterm 的功能。</p><p><img src="'+a+'" alt=""></p><h2 id="浏览扩展" tabindex="-1">浏览扩展 <a class="header-anchor" href="#浏览扩展" aria-label="Permalink to &quot;浏览扩展&quot;">​</a></h2><ol><li>点击左侧菜单栏中的<strong>扩展</strong>，进入扩展管理页面。</li><li>选择<strong>扩展市场</strong>标签页查看所有可用扩展，或切换到<strong>已安装扩展</strong>标签页查看已安装的扩展。</li><li>使用<strong>搜索栏</strong>按关键词过滤扩展。</li><li>点击扩展卡片查看详细信息，包括完整描述、功能列表和版本信息。</li></ol><h2 id="安装扩展" tabindex="-1">安装扩展 <a class="header-anchor" href="#安装扩展" aria-label="Permalink to &quot;安装扩展&quot;">​</a></h2><p><strong>从扩展市场安装</strong></p><ol><li>在扩展管理页面，浏览或搜索你需要的扩展。</li><li>点击扩展卡片查看详细信息。</li><li>点击<strong>安装</strong>按钮。</li><li>等待安装完成。</li></ol><p><strong>从本地文件安装</strong></p><ol><li>点击<strong>从文件安装</strong>按钮。</li><li>从本地选择扩展包文件（<code>.chaterm</code> 格式）。</li><li>Chaterm 会自动验证并安装扩展。</li></ol><div class="tip custom-block"><p class="custom-block-title">安装后自动启用</p><p>扩展在安装完成后会<strong>自动启用</strong>。你可以立即使用新功能，并可在<strong>已安装扩展</strong>标签页中管理该扩展。</p></div><h2 id="启用和禁用扩展" tabindex="-1">启用和禁用扩展 <a class="header-anchor" href="#启用和禁用扩展" aria-label="Permalink to &quot;启用和禁用扩展&quot;">​</a></h2><ol><li>进入<strong>已安装扩展</strong>标签页。</li><li>找到要切换状态的扩展。</li><li>点击<strong>启用</strong>按钮激活已禁用的扩展，或点击<strong>禁用</strong>按钮停用已激活的扩展。</li><li>更改立即生效 —— 无需重启。</li></ol><div class="warning custom-block"><p class="custom-block-title">核心扩展</p><p>禁用某些核心扩展可能会影响 Chaterm 的基本功能（例如终端渲染或连接处理）。仅在确定该扩展不是你工作流所必需时才禁用。</p></div><h2 id="配置扩展" tabindex="-1">配置扩展 <a class="header-anchor" href="#配置扩展" aria-label="Permalink to &quot;配置扩展&quot;">​</a></h2><p>部分扩展提供了可自定义行为的设置项：</p><ol><li>在<strong>已安装扩展</strong>标签页中，找到要配置的扩展。</li><li>点击<strong>配置</strong>按钮，打开设置对话框。</li><li>调整可用选项。常见的配置项包括： <ul><li>功能开关（开启/关闭）</li><li>显示选项（主题、布局）</li><li>行为参数（超时时间、默认值）</li><li>集成设置（API 密钥、端点）</li></ul></li><li>点击<strong>保存</strong>。新配置立即生效。</li></ol><p>有关全局扩展偏好设置，请参阅<a href="/docs/settings/extensions/">扩展设置</a>。</p><h2 id="更新扩展" tabindex="-1">更新扩展 <a class="header-anchor" href="#更新扩展" aria-label="Permalink to &quot;更新扩展&quot;">​</a></h2><p>当已安装的扩展有新版本可用时：</p><ol><li>扩展列表中该扩展旁会显示<strong>更新标记</strong>。</li><li>点击<strong>更新</strong>按钮升级到最新版本。</li><li>更新后你的现有配置会被保留。</li></ol><h2 id="卸载扩展" tabindex="-1">卸载扩展 <a class="header-anchor" href="#卸载扩展" aria-label="Permalink to &quot;卸载扩展&quot;">​</a></h2><ol><li>在<strong>已安装扩展</strong>标签页中，找到要卸载的扩展。</li><li>点击<strong>卸载</strong>按钮。</li><li>在弹出的对话框中确认操作。该扩展及其数据将从 Chaterm 中移除。</li></ol>',23),n=[s];function e(c,g,d,h,p,m){return t(),o("div",null,n)}const b=l(r,[["render",e]]);export{u as __pageData,b as default};
